  9	  ButtonVariant,
 10	  Form,
 11	  Modal,
 12	  ModalBoxFooter,
 13	  ModalProps,
 14	  ModalVariant,
 15	  Stack,
 16	  StackItem,
 17	} from "@patternfly/react-core";
 18	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 19	
 20	type TabModalProps<T extends K8sResourceCommon = K8sResourceCommon> = {
 21	  isOpen: boolean;
 22	  obj?: T;
 23	  onSubmit: (obj: T) => Promise<T | void>;
 24	  onClose: () => Promise<void> | void;
 25	  headerText: string;
 26	  children: React.ReactNode;
 27	  isDisabled?: boolean;
 28	  submitBtnText?: string;
 29	  modalVariant?: ModalVariant;
 30	  positionTop?: boolean;
 31	  submitBtnVariant?: ButtonVariant;
 32	  submitBtnType?: ButtonProps["type"];
 33	  titleIconVariant?: ModalProps["titleIconVariant"];
 34	};
 35	
 36	export type TabModalFC = <T extends K8sResourceCommon = K8sResourceCommon>(
 37	  props: TabModalProps<T>
 38	) => JSX.Element;
 39	
 40	const TabModal: TabModalFC = React.memo(
 41	  ({
 42	    obj,
 43	    onSubmit,
 44	    isOpen,
 45	    onClose,
 46	    headerText,
 47	    children,
 48	    isDisabled,
 49	    submitBtnText,
 50	    modalVariant,
 51	    positionTop = true,
 52	    submitBtnVariant,
 53	    titleIconVariant,
 54	    submitBtnType,
 55	  }) => {
 56	    const { t } = useNodeHealthCheckTranslation();
 57	
 58	    const [isSubmitting, setIsSubmitting] = React.useState(false);
 59	    const [error, setError] = React.useState(undefined);
 60	
 61	    const handleSubmit: React.MouseEventHandler<HTMLButtonElement> = (e) => {
 62	      e.preventDefault();
 63	      setIsSubmitting(true);
 64	      setError(undefined);
 65	
 66	      onSubmit(obj)
 67	        .then(onClose)
 68	        .catch(setError)
 69	        .finally(() => setIsSubmitting(false));
 70	    };
 71	
 72	    const closeModal = () => {
 73	      setError(undefined);
 74	      setIsSubmitting(false);
 75	
 76	      const promise = onClose();
 77	
 78	      if (promise) promise?.catch(setError);
 79	    };
 80	
 81	    return (
 82	      <Modal
 83	        variant={modalVariant ?? "small"}
 84	        position={positionTop ? "top" : undefined}
 85	        className="ocs-modal"
 86	        onClose={closeModal}
 87	        title={headerText}
 88	        titleIconVariant={titleIconVariant}
 89	        isOpen={isOpen}
 90	        id="tab-modal"
 91	      >
 92	        <Form>
 93	          {children}
 94	          {error && (
 95	            <StackItem>
 96	              <Alert
 97	                isInline
 98	                variant={AlertVariant.danger}
 99	                title={t("An error occurred")}
100	              >
101	                <Stack hasGutter>
102	                  <StackItem>{error.message}</StackItem>
103	                  {error?.href && (
104	                    <StackItem>
105	                      <a href={error.href} target="_blank" rel="noreferrer">
106	                        {error.href}
107	                      </a>
108	                    </StackItem>
109	                  )}
110	                </Stack>
111	              </Alert>
112	            </StackItem>
113	          )}
114	          <ModalBoxFooter>
115	            <Button
116	              onClick={handleSubmit}
117	              isDisabled={isDisabled || isSubmitting}
118	              isLoading={isSubmitting}
119	              variant={submitBtnVariant ?? "primary"}
120	              type={submitBtnType}
121	            >
122	              {submitBtnText || t("Save")}
123	            </Button>
124	            <Button onClick={closeModal} variant="link">
125	              {t("Cancel")}
126	            </Button>
127	          </ModalBoxFooter>
128	        </Form>
129	      </Modal>
130	    );
131	  }
132	);
133	
134	export default TabModal;

